query:
{
  serviceAccounts(
    where: {
      internalName: { eq: "default" }
      clusterRoleBindingSubjects_SOME: {
        clusterRoleBindings: { NOT: { idFromProvider: { eq: "" } } }
      }
    }
  ) {
    clusterRoleBindingSubjects {
      clusterRoleBindings {
        ...AssetFragment
      }
    }
  }
}
